/* XOR two byte arrays */
void xor_bytes(uint8_t *result, const uint8_t *input, const uint8_t *key, size_t len) {
    for (size_t i = 0; i < len; i++) {
        result[i] = input[i] ^ key[i];
    }
}

/* SubBytes transformation */
void sub_bytes(uint8_t *block) {
    for (int i = 0; i < AES_BLOCK_SIZE; i++) {
        block[i] = sbox[block[i]];
    }
}

/* ShiftRows transformation - row 0 unchanged, row 1 shift left 1, etc. */
void shift_rows(uint8_t *block) {
    uint8_t temp;
    /* Row 1: shift left 1 */
    temp = block[1];
    block[1] = block[5];
    block[5] = block[9];
    block[9] = block[13];
    block[13] = temp;

    /* Row 2: shift left 2 */
    temp = block[2];
    block[2] = block[10];
    block[10] = temp;
    temp = block[6];
    block[6] = block[14];
    block[14] = temp;

    /* Row 3: shift left 3 */
    temp = block[15];
    block[15] = block[11];
    block[11] = block[7];
    block[7] = block[3];
    block[3] = temp;
}

/* MixColumns transformation (simplified - actual implementation more complex) */
void mix_columns(uint8_t *block) {
    uint8_t tmp, tm, t;
    for (int i = 0; i < 4; i++) {
        t = block[i * 4];
        tmp = block[i * 4] ^ block[i * 4 + 1] ^ block[i * 4 + 2] ^ block[i * 4 + 3];
        tm = block[i * 4] ^ block[i * 4 + 1];
        tm = ((tm << 1) ^ (0x1b * (tm >> 7))) & 0xff;
        tmp ^= tm;
        tm = block[i * 4 + 1] ^ block[i * 4 + 2];
        tm = ((tm << 1) ^ (0x1b * (tm >> 7))) & 0xff;
        tmp ^= tm;
        tm = block[i * 4 + 2] ^ block[i * 4 + 3];
        tm = ((tm << 1) ^ (0x1b * (tm >> 7))) & 0xff;
        tmp ^= tm;
        tm = block[i * 4 + 3] ^ t;
        tm = ((tm << 1) ^ (0x1b * (tm >> 7))) & 0xff;
        tmp ^= tm;

        block[i * 4] ^= tmp;
        block[i * 4 + 1] ^= tmp;
        block[i * 4 + 2] ^= tmp;
        block[i * 4 + 3] ^= tmp;
    }
}

/* AddRoundKey: XOR block with round key */
void add_round_key(uint8_t *block, const uint8_t *round_key) {
    xor_bytes(block, block, round_key, AES_BLOCK_SIZE);
}

/* PKCS#7 padding */
int add_padding(uint8_t *input, size_t input_len, size_t block_size) {
    size_t padding = block_size - (input_len % block_size);
    for (size_t i = 0; i < padding; i++) {
        input[input_len + i] = (uint8_t)padding;
    }
    return input_len + padding;
}

/* Simple AES-128-ECB encrypt (one block for demonstration) */
void aes128_encrypt_block(uint8_t *plaintext, const uint8_t *key) {
    uint8_t state[AES_BLOCK_SIZE];

    /* Copy plaintext to state */
    memcpy(state, plaintext, AES_BLOCK_SIZE);

    /* Initial round key addition */
    add_round_key(state, key);

    /* Main rounds (simplified - 9 rounds for full AES) */
    for (int round = 1; round <= 1; round++) {
        sub_bytes(state);
        shift_rows(state);
        mix_columns(state);
        add_round_key(state, key);  /* In real AES, use round key derived from key schedule */
    }

    /* Final round (no MixColumns) */
    sub_bytes(state);
    shift_rows(state);
    add_round_key(state, key);

    /* Copy state to ciphertext */
    memcpy(plaintext, state, AES_BLOCK_SIZE);
}

/* CBC Mode Encryption */
void aes_cbc_encrypt(uint8_t *ciphertext, const uint8_t *plaintext, 
                     size_t len, const uint8_t *key, uint8_t *iv) {
    uint8_t input_block[AES_BLOCK_SIZE];
    uint8_t prev_block[AES_BLOCK_SIZE];

    memcpy(prev_block, iv, AES_BLOCK_SIZE);

    for (size_t i = 0; i < len; i += AES_BLOCK_SIZE) {
        /* XOR with previous ciphertext block (or IV for first block) */
        for (int j = 0; j < AES_BLOCK_SIZE; j++) {
            input_block[j] = plaintext[i + j] ^ prev_block[j];
        }

        /* Encrypt the block */
        aes128_encrypt_block(input_block, key);

        /* Store ciphertext and update previous block */
        memcpy(&ciphertext[i], input_block, AES_BLOCK_SIZE);
        memcpy(prev_block, input_block, AES_BLOCK_SIZE);
    }
}

/* Print hex bytes */
void print_hex(const char *label, const uint8_t *data, size_t len) {
    printf("%s: ", label);
    for (size_t i = 0; i < len; i++) {
        printf("%02x", data[i]);
    }
    printf("\n");
}

